	/*********************************************************************
	*	@function highlow
	*	@param $stockprices
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  highlow($stockprices)
	{
		/*Calculate the high10/20 and low10/20 values and breakout 20/55 values*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//Assumes stockprices has been created elsewhere, had its date and symbol set, and then passed into here.
		
		$this->Sethigh10( $stockprices->highprice10() );
		$this->Setlow10( $stockprices->lowprice10() );
		$this->Sethigh20( $stockprices->highprice20() );
		$this->Setlow20( $stockprices->lowprice20() );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculatebreakouts
	*	@param $stockprices
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculatebreakouts($stockprices)
	{
		/*Calculate the 20 and 55 day breakout values*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//These values are either the high or the low 20/55 values depending on which side we are closest to.  Requires that stockprices is passed in, and that the date and symbol has already been set.  Assumes that the db row for the given date has also been retrieved into the object's variables.
		
		$this->Setbreakoutlow20( $stockprices->lowprice20() );
		$this->Setbreakoutlow55( $stockprices->lowprice55() );
		$this->Setbreakouthigh20( $stockprices->highprice20() );
		$this->Setbreakouthigh55( $stockprices->highprice55() );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculatevolatility
	*	@param $technicalanalysis
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculatevolatility($technicalanalysis)
	{
		/*To calculate the volatility N for the day.  Used for risk adjustment in unit size*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//Assumes technicalanaylsis has been created and set with the stock and date
		//N = ( 19 X PreviousN + TrueRange0 ) / 20
		$this->Setvolatility( ( ( 19 * $this->GetPrevVolatility() ) + $technicalanalysis->Gettruerange() ) / 20 );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculate
	*	@param $date, $symbol
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculate($date, $symbol)
	{
		/*Calculate the turtledata for today*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		require_once( $MODELDIR . "/technicalanalysis.class.php" );
		require_once( $MODELDIR . "/stockprices.class.php" );
		$this->Setdate( $date );
		$this->Setsymbol( $symbol );
		
		//This would normally be a constructor job, but since the constructor is autogenned
		
		$technicalanalysis = new technicalanaylsis();
		$stockprices = new stockprices();
		
		$stockprices->Setdate( $this->Getdate() );
		$stockprices->Setsymbol( $this->Getsymbol() );
		
		$technicalanalysis->Setdate( $this->Getdate() );
		$technicalanalysis->Setsymbol( $this->Getsymbol() );
		
		$this->highlow( $stockprices );
		$this->Calculatebreakouts( $stockprices );
		$this->calculatevolatility( $technicalanalysis );
		$this->normalizeprice( $stockprices, $technicalanalysis );
		
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function normalizeprice
	*	@param $stockprices, $technicalanalysis
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  normalizeprice($stockprices, $technicalanalysis)
	{
		/*Calculate the normalized price*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		/*Normalized price of the market - Current Price - 90day EMA divided by N */
		
		$this->Setnormalizedprice( ( $stockprices->Getday_close() - $technicalanalysis->Getema90() ) / $this->Getvolatility() );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculateignore20
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculateignore20()
	{
		/*Calculate if the following 20day signal should be ignored or not*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//Has to do with the previous signals being a winning trade.
		//Losing trades automatically set this to false.
		
		$this->Setignore20( 0 );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculatepositionadd
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculatepositionadd()
	{
		/*When a breakout occurs, the next add price is 1/2N*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//when the price goes 1/2N pass the breakout
		
		$this->positionadd = $this->breakouthigh55 + 0.5 * $this->volatility;
		
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculatesellallprice
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculatesellallprice()
	{
		/*if the price is going against the breakout and hits the 20 day breakout before the 10 day high sell all*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		
		
		//Assuming long stocks
		
		if( $this->low10 > ( $this->breakout10 - ( 2 * $this->volatility ) ) )
		$this->sellallprice = $this->low10; else $this->sellallprice = $this->breakout10 - ( 2 * $this->volatility );
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculatetruerange
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculatetruerange()
	{
		/*Calculate the true range of the day's price*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		/*True Range = MAX( High0-Low0, High0-Close1, Close1 - Low0 )*/
		                
		$atr = $this->high0 - $this->low0;
		if( $this->high0 - $this->close1 > $atr ) $atr = $this->high0 - $this->close1;
		if( $this->close1 - $this->low0 > $atr ) $atr = $this->close1 - $this->low0;
		$this->truerange = $atr;
		
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculateunit
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculateunit()
	{
		/*calculate the Unit - percentage of the account to invest*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		/*Unit = floor(  (1% of account) / N * dollars per point  ) */
		$this->unit = 1 / $this->volatility;
		
		//If we don't have a return in the body in codemeta, return
		return ;
	}
	/*********************************************************************
	*	@function calculateturtledata
	*	@param 
	*	@see 
	*	@return 
	*********************************************************************/
	/**//*C  C*/ function  calculateturtledata()
	{
		/*calculate all data points*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: */
		/*	Use Case When: */
		/*	Use Case What: */
		/*	Use Case Why: */
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		$this->breakouthigh55 = $this->breakouthigh55();
		$this->breakouthigh20 = $this->breakouthigh20();
		$this->breakoutlow55 = $this->breakoutlow55();
		$this->breakoutlow20 = $this->breakoutlow20();
		$this->high10 = $this->high10();
		$this->high20 = $this->high20();
		$this->low10 = $this->low10();
		$this->low20 = $this->low20();
		$this->calculatetruerange();
		$this->calculatevolatility();
		$this->calculateunit();
		$this->calculatepositionadd();
		$this->calculatesellallprice();
		$this->calculatenormalizedprice();
		$this->calculateignore20();
		
		//If we don't have a return in the body in codemeta, return
		return ;
	}
